import torch
import torch.nn as nn

class M(nn.Module):
    def __init__(self, use_gpu):
        super().__init__()
        self.use_gpu = use_gpu
        self.bias = torch.randn(10)  # plain Tensor, not a Parameter/buffer; stays on CPU
    def forward(self, x):
        if self.use_gpu:
            # x is on CUDA but bias remains on CPU
            return x + self.bias  # RuntimeError: Expected all tensors to be on the same device
        else:
            return x + self.bias

x = torch.randn(4, 10, device='cuda')
m = M(use_gpu=True).cuda()  # .cuda() won't move plain attributes
m(x)

import torch
import torch.nn as nn

class Net(nn.Module):
    def __init__(self):
        super().__init__()
        self.big = nn.Linear(64, 64)
        self.small = nn.Linear(64, 64)
    def forward(self, x):
        # Shape-dependent control flow
        if x.size(1) > 32:
            return self.big(x)
        else:
            return self.small(x)

net = Net()
example = torch.randn(8, 64)  # seq_len=64 -> traces the 'big' branch
traced = torch.jit.trace(net, example)
# Later: runtime input takes the 'small' branch logically, but trace fixed the 'big' path
x_runtime = torch.randn(8, 16)
out = traced(x_runtime)  # silently uses 'big' branch despite size(1)=16
